/*
 * cosf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly cosf  (test_cosf_opt.elf)
 *   2. Linked with toolchain's default cosf        (test_cosf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

static void emit(float x)
{
    float r = cosf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}

/* ------------------------------------------------------------------ */
/* Test points                                                         */
/* ------------------------------------------------------------------ */

/* 1. Special values */
static void test_special(void)
{
    /* Zeros */
    emit(0.0f);
    emit(-0.0f);

    /* NaN */
    emit_u(0x7fc00000u); /* qNaN */
    emit_u(0x7f800001u); /* sNaN */
    emit_u(0xffc00000u); /* -NaN */

    /* Infinity */
    emit_u(0x7f800000u); /* +Inf */
    emit_u(0xff800000u); /* -Inf */
}

/* 2. Tiny values: cos(x) ~ 1 */
static void test_tiny(void)
{
    emit_u(0x00000001u); /* min denorm */
    emit_u(0x80000001u);
    emit_u(0x00400000u); /* mid denorm */
    emit_u(0x80400000u);
    emit_u(0x007fffffu); /* max denorm */
    emit_u(0x807fffffu);
    emit(FLT_MIN);
    emit(-FLT_MIN);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-10f);
    emit(-1.0e-10f);
}

/* 3. Known mathematical values */
static void test_known(void)
{
    float pi   = 3.14159265358979323846f;
    float pi_2 = 1.57079632679489661923f;
    float pi_3 = 1.04719755119659774615f;
    float pi_4 = 0.78539816339744830962f;
    float pi_6 = 0.52359877559829887308f;

    emit(pi_6);
    emit(pi_4);
    emit(pi_3);
    emit(pi_2);
    emit(pi);
    emit(2.0f * pi);
    emit(-pi_6);
    emit(-pi_4);
    emit(-pi_2);
    emit(-pi);
    emit(3.0f * pi_2);
    emit(pi_2 + 0.001f);
    emit(pi + 0.001f);
    emit(pi - 0.001f);
}

/* 4. Large arguments */
static void test_large(void)
{
    float vals[] = {
        10.0f, 100.0f, 1000.0f, 100000.0f, 1000000.0f,
        -10.0f, -1000.0f,
        3.14159265f * 100.0f,
        3.14159265f * 1000.0f,
        1.0e10f, 1.0e20f,
        -1.0e10f, -1.0e20f,
        FLT_MAX, -FLT_MAX,
    };
    int n = sizeof(vals) / sizeof(vals[0]);
    for (int i = 0; i < n; i++)
        emit(vals[i]);
}

/* 5. Quadrant transitions */
static void test_quadrant(void)
{
    float pi_2 = 1.5707963267948966f;
    float offsets[] = { -1e-5f, 0.0f, 1e-5f };
    int noff = sizeof(offsets) / sizeof(offsets[0]);

    for (int k = 1; k <= 8; k++) {
        float boundary = (float)((double)k * (double)pi_2);
        for (int j = 0; j < noff; j++)
            emit(boundary + offsets[j]);
    }
}

/* 6. Worst-case argument reduction */
static void test_hard(void)
{
    float cases[] = {
        u2f(0x40490fdbu), /* pi as float */
        u2f(0x40c90fdbu), /* 2*pi as float */
        u2f(0x4096cbe4u), /* 3*pi/2 */
        4.0f, 16.0f, 64.0f, 256.0f,
    };
    int n = sizeof(cases) / sizeof(cases[0]);
    for (int i = 0; i < n; i++) {
        emit(cases[i]);
        emit(-cases[i]);
    }
}

/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f490fdbu; /* pi/4 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

int main(void)
{
    test_special();
    test_tiny();
    test_known();
    test_large();
    test_quadrant();
    test_hard();
    test_sweep();
    test_exhaustive_small();
    return 0;
}

